notice_title = #{noticeTitle}, notice_type = #{noticeType}, notice_content = #{noticeContent}, status = #{status}, biz_category = #{bizCategory}, notice_summary = #{noticeSummary}, receiver_scope = #{receiverScope}, receiver_user_ids = #{receiverUserIds}, action_type = #{actionType}, action_path = #{actionPath}, action_target_id = #{actionTargetId}, pinned = #{pinned}, publish_time = #{publishTime}, expire_time = #{expireTime}, update_by = #{updateBy}, update_time = sysdate()
