select n.notice_id, n.notice_title, n.notice_type, cast(n.notice_content as char) as notice_content, n.status, n.biz_category, n.notice_summary, n.receiver_scope, n.receiver_user_ids, n.action_type, n.action_path, n.action_target_id, n.pinned, n.publish_time, n.expire_time, n.create_by, n.create_time, n.update_by, n.update_time, n.remark, case when r.notice_id is null then '0' else '1' end as read_flag, r.read_time from sys_notice n left join sys_notice_read r on r.notice_id = n.notice_id and r.user_id = #{userId} where n.status = '0'
and n.biz_category = #{bizCategory}
and (n.notice_title like concat('%', #{keyword}, '%') or n.notice_summary like concat('%', #{keyword}, '%') or cast(n.notice_content as char) like concat('%', #{keyword}, '%'))
and ( n.receiver_scope = 'ALL'
or n.receiver_scope = #{receiverScope}
or (n.receiver_scope = 'CUSTOM' and find_in_set(cast(#{userId} as char), n.receiver_user_ids)) ) and (n.publish_time is null or n.publish_time <= sysdate()) and (n.expire_time is null or n.expire_time >= sysdate())
and r.notice_id is null
and r.notice_id is not null
order by case when n.pinned = '1' then 0 else 1 end, coalesce(n.publish_time, n.create_time) desc, n.notice_id desc
limit #{limit}

select sum(case when n.biz_category = 'MESSAGE' and r.notice_id is null then 1 else 0 end) as unreadMessageCount, sum(case when n.biz_category = 'NOTICE' then 1 else 0 end) as noticeCount, sum(case when r.notice_id is null then 1 else 0 end) as totalUnreadCount from sys_notice n left join sys_notice_read r on r.notice_id = n.notice_id and r.user_id = #{userId} where n.status = '0' and ( n.receiver_scope = 'ALL'
